arguments.file_text:
@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <nav class="settings-sidebar">
        <h5 class="px-3 py-2 mb-1 text-muted">Settings</h5>
        <ul class="nav flex-column">
            @foreach (var section in _sections)
            {
                <li class="nav-item">
                    <button class="nav-link @(section == _activeSection ? "active" : "")"
                            @onclick="() => _activeSection = section">
                        <span class="me-2">@SectionIcon(section)</span>@section
                    </button>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";

    private static string SectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-layout {
    display: flex;
    min-height: calc(100vh - 100px);
    gap: 0;
}

.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1rem 0;
}

.settings-sidebar .nav-link {
    color: #495057;
    padding: 0.6rem 1.25rem;
    border-radius: 0;
    border-left: 3px solid transparent;
    font-weight: 500;
    cursor: pointer;
    text-align: left;
    width: 100%;
    background: none;
    border-top: none;
    border-right: none;
    border-bottom: none;
    border-left: 3px solid transparent;
}

.settings-sidebar .nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

.settings-sidebar .nav-link.active {
    color: #0d6efd;
    background: #e7f1ff;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.settings-content {
    flex: 1;
    padding: 1.5rem 2rem;
    max-width: 800px;
}

/* Toast / status message */
.settings-toast {
    position: fixed;
    top: 1rem;
    right: 1rem;
    z-index: 1055;
    min-width: 280px;
    animation: slideIn 0.3s ease-out;
}

@keyframes slideIn {
    from { transform: translateX(100%); opacity: 0; }
    to   { transform: translateX(0);    opacity: 1; }
}

/* Section headings */
.settings-section h3 {
    font-size: 1.4rem;
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.settings-section .section-desc {
    color: #6c757d;
    margin-bottom: 1.5rem;
}

/* Avatar preview */
.avatar-preview {
    width: 96px;
    height: 96px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #dee2e6;
}

/* Expandable panel */
.expand-panel-header {
    cursor: pointer;
    user-select: none;
}

/* Confirmation dialog overlay */
.confirm-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.4);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1060;
}

.confirm-dialog {
    background: #fff;
    border-radius: 8px;
    padding: 1.5rem;
    min-width: 360px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.2);
}

/* Live preview box */
.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1.25rem;
    margin-top: 1rem;
    transition: all 0.3s ease;
}

.appearance-preview.dark {
