@using sv_e8a090ab9b4b4ba2b054e97d8b1e9838.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Profile</h3>
    <p class="section-desc">Manage your personal information and public profile.</p>

    @if (_loading)
    {
        <div class="text-center py-4"><div class="spinner-border" role="status"></div></div>
    }
    else
    {
        <div class="d-flex align-items-start gap-4 mb-4">
            <div class="text-center">
                <img src="@_avatarUrl" alt="Avatar" class="avatar-preview mb-2" />
                <div class="text-muted small text-truncate" style="max-width: 120px;" title="@_avatarUrl">@_avatarUrl</div>
            </div>
            <div class="flex-grow-1">
                <div class="mb-3">
                    <label class="form-label fw-semibold">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label fw-semibold">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>
            </div>
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Bio</label>
            <textarea class="form-control" rows="3" @bind="_bio"></textarea>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
        </div>
    }

    @if (_showToast)
    {
        <div class="settings-toast alert alert-success alert-dismissible fade show" role="alert">
            ✓ Profile saved successfully.
            <button type="button" class="btn-close" @onclick="() => _showToast = false"></button>
        </div>
    }
</div>

@code {
    private bool _loading = true, _saving, _showToast;
    private string _displayName = "", _email = "", _avatarUrl = "", _bio = "";
    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _avatarUrl = p.AvatarUrl;
        _bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _saving = false;
        _showToast = true;
        _ = DismissToastAsync();
    }

    private void Discard()
    {
        if (_savedProfile is not null)
            ApplyProfile(_savedProfile);
    }

    private async Task DismissToastAsync()
    {
        await Task.Delay(3000);
        _showToast = false;
        await InvokeAsync(StateHasChanged);
    }
}

