@using sv_e8a090ab9b4b4ba2b054e97d8b1e9838.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Notifications</h3>
    <p class="section-desc">Choose how and when you want to be notified.</p>

    @if (_loading)
    {
        <div class="text-center py-4"><div class="spinner-border" role="status"></div></div>
    }
    else
    {
        <div class="card mb-4">
            <div class="card-body">
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                    <label class="form-check-label fw-semibold" for="emailNotif">Email Notifications</label>
                    <div class="text-muted small">Receive notifications via email</div>
                </div>
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                    <label class="form-check-label fw-semibold" for="pushNotif">Push Notifications</label>
                    <div class="text-muted small">Receive browser push notifications</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                    <label class="form-check-label fw-semibold" for="weeklyDigest">Weekly Digest</label>
                    <div class="text-muted small">Get a weekly summary of activity</div>
                </div>
            </div>
        </div>

        <h5>Muted Channels</h5>
        <p class="text-muted small">Select channels to mute. Muted channels won't send notifications.</p>
        <div class="card mb-4">
            <div class="card-body">
                @foreach (var channel in _allChannels)
                {
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" id="ch-@channel"
                               checked="@_mutedChannels.Contains(channel)"
                               @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="ch-@channel">#@channel</label>
                    </div>
                }
            </div>
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>

        @if (_showToast)
        {
            <div class="settings-toast alert alert-success alert-dismissible fade show mt-3" role="alert">
                ✓ Notification preferences saved.
                <button type="button" class="btn-close" @onclick="() => _showToast = false"></button>
            </div>
        }
    }
</div>

@code {
    private bool _loading = true, _saving, _showToast;
    private bool _emailNotifications, _pushNotifications, _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private readonly List<string> _allChannels = MockSettingsService.GetAllChannels();

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = [.. prefs.MutedChannels];
        _loading = false;
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted) _mutedChannels.Add(channel);
        else _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, [.. _mutedChannels]);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        _showToast = true;
        _ = DismissToastAsync();
    }

    private async Task DismissToastAsync()
    {
        await Task.Delay(3000);
        _showToast = false;
        await InvokeAsync(StateHasChanged);
    }
}

