@using sv_e8a090ab9b4b4ba2b054e97d8b1e9838.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Security</h3>
    <p class="section-desc">Manage your password, two-factor authentication, and active sessions.</p>

    @if (_loading)
    {
        <div class="text-center py-4"><div class="spinner-border" role="status"></div></div>
    }
    else
    {
        @* --- Change Password Panel --- *@
        <div class="card mb-4">
            <div class="card-header expand-panel-header d-flex justify-content-between align-items-center"
                 @onclick="() => _passwordExpanded = !_passwordExpanded">
                <span class="fw-semibold">Change Password</span>
                <span>@(_passwordExpanded ? "▲" : "▼")</span>
            </div>
            @if (_passwordExpanded)
            {
                <div class="card-body">
                    @if (_settings?.LastPasswordChange is not null)
                    {
                        <p class="text-muted small mb-3">
                            Last changed: @_settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                        </p>
                    }
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>

                    @if (!string.IsNullOrEmpty(_passwordError))
                    {
                        <div class="alert alert-danger py-2">@_passwordError</div>
                    }
                    @if (_passwordSuccess)
                    {
                        <div class="alert alert-success py-2">Password updated successfully.</div>
                    }

                    <button class="btn btn-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @if (_changingPassword)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Update Password
                    </button>
                </div>
            }
        </div>

        @* --- Two-Factor Authentication --- *@
        <div class="card mb-4">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <span class="fw-semibold">Two-Factor Authentication</span>
                    <div class="mt-1">
                        @if (_twoFactorEnabled)
                        {
                            <span class="badge bg-success">Enabled</span>
                        }
                        else
                        {
                            <span class="badge bg-secondary">Disabled</span>
                        }
                    </div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled"
                           style="transform: scale(1.4);" />
                </div>
            </div>
        </div>

        @* --- Active Sessions --- *@
        <h5>Active Sessions</h5>
        <div class="table-responsive">
            <table class="table table-hover align-middle">
                <thead class="table-light">
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @if (_settings is not null)
                    {
                        @foreach (var session in _settings.Sessions)
                        {
                            var isCurrentSession = session == _settings.Sessions[0];
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrentSession)
                                    {
                                        <span class="badge bg-info ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (!isCurrentSession)
                                    {
                                        <button class="btn btn-outline-danger btn-sm"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    }
                </tbody>
            </table>
        </div>
    }

    @* --- Revoke Confirmation Dialog --- *@
    @if (_sessionToRevoke is not null)
    {
        <div class="confirm-overlay" @onclick="CancelRevoke">
            <div class="confirm-dialog" @onclick:stopPropagation="true">
                <h5>Revoke Session</h5>
                <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in @_sessionToRevoke.Location?</p>
                <div class="d-flex gap-2 justify-content-end">
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                        @if (_revoking)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Revoke
                    </button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private SecuritySettings? _settings;

    // Password change
    private bool _passwordExpanded, _changingPassword, _passwordSuccess;
    private string _currentPassword = "", _newPassword = "", _confirmPassword = "", _passwordError = "";

    // 2FA
    private bool _twoFactorEnabled;

    // Session revocation
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _settings.TwoFactorEnabled;
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = "";
        _passwordSuccess = false;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        _changingPassword = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = _newPassword = _confirmPassword = "";
        _changingPassword = false;
        _passwordSuccess = true;
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _sessionToRevoke = null;
        _revoking = false;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

