@using sv_e8a090ab9b4b4ba2b054e97d8b1e9838.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Appearance</h3>
    <p class="section-desc">Customize the look and feel of the application.</p>

    @if (_loading)
    {
        <div class="text-center py-4"><div class="spinner-border" role="status"></div></div>
    }
    else
    {
        @* --- Theme --- *@
        <div class="mb-4">
            <label class="form-label fw-semibold">Theme</label>
            <div class="d-flex gap-3">
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                               value="@theme" checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="theme-@theme">@theme</label>
                    </div>
                }
            </div>
        </div>

        @* --- Font Size --- *@
        <div class="mb-4">
            <label class="form-label fw-semibold">Font Size</label>
            <div class="d-flex gap-3">
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                               value="@size" checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="fs-@size">@size</label>
                    </div>
                }
            </div>
        </div>

        @* --- Language --- *@
        <div class="mb-4">
            <label class="form-label fw-semibold">Language</label>
            <select class="form-select" style="max-width: 280px;" @bind="_language">
                @foreach (var lang in _languages)
                {
                    <option value="@lang">@lang</option>
                }
            </select>
        </div>

        @* --- Compact Mode --- *@
        <div class="form-check form-switch mb-4">
            <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
            <label class="form-check-label fw-semibold" for="compactMode">Compact Mode</label>
            <div class="text-muted small">Reduce spacing and padding for a denser layout</div>
        </div>

        @* --- Live Preview --- *@
        <h5>Preview</h5>
        <div class="appearance-preview @PreviewClasses()">
            <h6 style="margin-bottom: 0.5rem;">Sample Heading</h6>
            <p style="margin-bottom: 0.5rem;">
                This is how your content will look with the selected settings.
                The <strong>@_theme</strong> theme is applied with <strong>@_fontSize</strong> font size
                in <strong>@_language</strong>.
            </p>
            <button class="btn @(_theme == "Dark" ? "btn-outline-light" : "btn-outline-primary") btn-sm">
                Sample Button
            </button>
        </div>

        <div class="mt-4">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save
            </button>
        </div>

        @if (_showToast)
        {
            <div class="settings-toast alert alert-success alert-dismissible fade show" role="alert">
                ✓ Appearance settings saved.
                <button type="button" class="btn-close" @onclick="() => _showToast = false"></button>
            </div>
        }
    }
</div>

@code {
    private bool _loading = true, _saving, _showToast;
    private string _theme = "Light", _fontSize = "Medium", _language = "English";
    private bool _compactMode;

    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Portuguese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string PreviewClasses()
    {
        var classes = _theme.ToLowerInvariant();
        classes += $" font-{_fontSize.ToLowerInvariant()}";
        if (_compactMode) classes += " compact";
        return classes;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        await SettingsService.SaveAppearanceAsync(new AppearanceSettings(_theme, _fontSize, _language, _compactMode));
        _saving = false;
        _showToast = true;
        _ = DismissToastAsync();
    }

    private async Task DismissToastAsync()
    {
        await Task.Delay(3000);
        _showToast = false;
        await InvokeAsync(StateHasChanged);
    }
}

